#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = fract(vUv);
vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1 + rand_frame.xy;
vec2 d = uTexSize.zw*12;
vec3 dx = GetBlur3(vUvOriginal + vec2(1,0)*d) - GetBlur3(vUvOriginal -vec2(1,0)*d);
vec3 dy = GetBlur3(vUvOriginal + vec2(0,1)*d) - GetBlur3(vUvOriginal -vec2(0,1)*d);

vec2 uvx = vUv
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*0
           - vec2(dx.x,dy.x)*uTexSize.zw*8;
    ret.x = texture( sampler_fc_main, uvx ).x
          - (GetBlur3(uvx)-texture( sampler_fc_main, uvx )).x*0.1
          - 0.024;

vec2 uvy = vUvOriginal
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*4
           - vec2(dx.x,dy.x)*uTexSize.zw*4
           + vec2(dx.y,dy.y)*uTexSize.zw*8;

ret.y = tex2d(sampler_fc_main,uvy).y
      + (texture(sampler_noise_lq, dither_uv).xyz-0.5)*0.1
      - 0.012
      + (tex2d(sampler_pc_main,vUvOriginal).z)*0.2;


vec2 uvz = vUvOriginal
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*2
           + vec2(dy.x,-dx.x)*uTexSize.zw*64
           + vec2(dx.z,dy.z)*uTexSize.zw*0;
ret.z = tex2d(sampler_fc_main,uvz).z
      + (tex2d(sampler_fc_main,uvz).z-GetBlur2(uvz).z)*0.2
      + (texture(sampler_noise_lq, dither_uv).xyz)*0.1
      - GetBlur3(vUvOriginal).x
      - clamp01(1-GetBlur2(vUvOriginal).x)*0.04;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 ac = vec2(q1,q2);
vec2 mu = vec2(q3,q4);
vec2 c = vec2(q5,q6);
vec2 d = vec2(q7,q8);

vec2 z = (vUv-0.5)*uAspect.wz;

// (c*z + d)
vec2 czd = vec2(z.x*c.x-z.y*c.y,z.x*c.y-z.y*c.x)*uAspect.yx + d;
// mu/(cz+d)
vec2 moebius = vec2( mu.x*czd.x + mu.y*czd.y , mu.y*czd.x-mu.x*czd.y )/(czd.x*czd.x+czd.y*czd.y) + ac;

    d = uTexSize.zw*4;
    float1 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) ).x;
    float1 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) ).x;

moebius = 0.5 + (1.0 - abs( fract( moebius * 0.5  + vec2(dx,dy)*.01) * 2 - 1.0 )-0.5)*0.99;

ret.x = GetPixel(moebius).y;
ret.z = GetPixel(vUv).x;
ret.y = GetBlur1(moebius).z;

ret = tex2d(sampler_rand00, moebius);
ret = mix(ret,vec3(-1,-2,1),GetBlur2(vUv-vec2(dx,dy)*0.02).x*0.4);
ret = mix(ret,vec3(0,-0.1,-0.2),GetBlur2(moebius).z*1.4);
ret = mix(ret,ret*0.6-0.2,GetPixel(moebius).y*1);
ret = mix(ret,vec3(1.6,0,0.6),GetPixel(moebius).z*0.38);
ret = mix(ret,vec3(2,4,3),GetPixel(vUv-vec2(dx,dy)*0.012).x*0.2);
//ret = GetPixel(vUv);
ret-=roam_sin*roam_cos.zxy;

  fragColor = ret;
}
